    ADD CONSTRAINT external_git_oauth_grants_pkey PRIMARY KEY (user_id, provider_instance_id);

ALTER TABLE ONLY public.external_git_oauth_grants
    ADD CONSTRAINT external_git_oauth_grants_provider_account_key UNIQUE (provider_instance_id, provider_account_id);

