    ADD CONSTRAINT external_git_project_links_project_provider_key UNIQUE (project_id, provider_instance_id);

ALTER TABLE ONLY public.git_bundle_artifacts
    ADD CONSTRAINT git_bundle_artifacts_object_key_key UNIQUE (object_key);

ALTER TABLE ONLY public.git_bundle_artifacts
    ADD CONSTRAINT git_bundle_artifacts_pkey PRIMARY KEY (id);

