    ADD CONSTRAINT git_pending_authors_pkey PRIMARY KEY (project_id, user_id);

ALTER TABLE ONLY public.git_pending_guest_authors
    ADD CONSTRAINT git_pending_guest_authors_pkey PRIMARY KEY (project_id, display_name);

ALTER TABLE ONLY public.git_repositories
    ADD CONSTRAINT git_repositories_pkey PRIMARY KEY (project_id);

ALTER TABLE ONLY public.git_sync_states
    ADD CONSTRAINT git_sync_states_pkey PRIMARY KEY (project_id);

ALTER TABLE ONLY public.external_git_checkpoint_queue
    ADD CONSTRAINT external_git_checkpoint_queue_pkey PRIMARY KEY (project_id);

ALTER TABLE ONLY public.external_git_pending_authors
    ADD CONSTRAINT external_git_pending_authors_pkey PRIMARY KEY (project_id, user_id);

ALTER TABLE ONLY public.external_git_pending_guest_authors
    ADD CONSTRAINT external_git_pending_guest_authors_pkey PRIMARY KEY (project_id, display_name);

ALTER TABLE ONLY public.external_git_project_links
    ADD CONSTRAINT external_git_project_links_pkey PRIMARY KEY (project_id);

ALTER TABLE ONLY public.local_accounts
    ADD CONSTRAINT local_accounts_pkey PRIMARY KEY (user_id);

ALTER TABLE ONLY public.object_deletion_queue
    ADD CONSTRAINT object_deletion_queue_pkey PRIMARY KEY (object_key);

ALTER TABLE ONLY public.oidc_states
    ADD CONSTRAINT oidc_states_pkey PRIMARY KEY (state);

ALTER TABLE ONLY public.org_oidc_group_role_mappings
    ADD CONSTRAINT org_oidc_group_role_mappings_pkey PRIMARY KEY (organization_id, group_name);

ALTER TABLE ONLY public.organization_memberships
    ADD CONSTRAINT organization_memberships_pkey PRIMARY KEY (organization_id, user_id);

ALTER TABLE ONLY public.organizations
    ADD CONSTRAINT organizations_pkey PRIMARY KEY (id);

ALTER TABLE ONLY public.personal_access_tokens
    ADD CONSTRAINT personal_access_tokens_pkey PRIMARY KEY (id);

ALTER TABLE ONLY public.personal_access_tokens
    ADD CONSTRAINT personal_access_tokens_token_fingerprint_key UNIQUE (token_fingerprint);

ALTER TABLE ONLY public.project_assets
    ADD CONSTRAINT project_assets_object_key_key UNIQUE (object_key);

ALTER TABLE ONLY public.project_assets
